const b = $input.first().json.body || $input.first().json;
const { iso, design, cloudinaryUrl } = b;
if (!iso) throw new Error('Missing: iso');
if (!design || !['D1','D2','D3','D4'].includes(design)) throw new Error('Invalid design — expected D1/D2/D3/D4');
if (!cloudinaryUrl) throw new Error('Missing: cloudinaryUrl');
return [{ json: { iso: iso.toUpperCase(), design, cloudinaryUrl } }];

const { iso, design, cloudinaryUrl } = $('Validate Input6').first().json;
const { printfulProductId, shopifyProductId } = $input.first().json;

if (!shopifyProductId) throw new Error('Create Product renvoyé une erreur : ' + JSON.stringify($input.first().json));

const secret = '82384b03f99d42502ddc3fc3eb1c8d0416786f2193f837900fa34bc54fe748fc';

const callbackPayload = {
  event: 'wfb.product_published',
  iso,
  design,
  shopifyProductId: String(shopifyProductId),
  printfulProductId: Number(printfulProductId)
};

const bodyStr = JSON.stringify(callbackPayload);
// $hmac() : built-in n8n, pas besoin de module externe
const sig = $hmac(bodyStr, secret, 'sha256');

return [{ json: { bodyStr, sig, shopifyProductId, printfulProductId, iso, design } }];
